"""Run from your insightforge project root:  python3 install_stage5.py"""
import base64
from pathlib import Path
ROOT = Path(__file__).parent
FILES = {
  "backend/app/schemas/investigation.py": "",
  "backend/app/services/result_validator.py": "",
  "backend/app/services/orchestrator.py": "",
  "backend/app/agents/insight_generator.py": "",
  "backend/app/api/routes/investigate.py": "",
  "backend/tests/test_result_validator.py": "",
  "backend/tests/test_insight_generator.py": ""
}
for rel, b64 in FILES.items():
    p = ROOT / rel
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_bytes(base64.b64decode(b64))
    print(f"  wrote {rel}")
print("\nDone! Now run: make test")